        if (!zipFile.isFile()) {
            throw new IOException("Specified path is not a file: " + zipFilePath);
        }
        if (!zipFile.canRead()) {
            throw new SecurityException("Insufficient permissions to read ZIP file: " + zipFilePath);
        }

        // Create the target extraction directory if it does not exist
        File extractDir = new File(extractPath);
        if (!extractDir.exists()) {
            if (!extractDir.mkdirs()) {
                throw new IOException("Failed to create extraction directory: " + extractPath);
            }
        }
        if (!extractDir.isDirectory()) {
            throw new IOException("Extraction path is not a directory: " + extractPath);
        }
        if (!extractDir.canWrite()) {
            throw new SecurityException("Insufficient permissions to write to extraction directory: " + extractPath);
        }

        // Resolve the canonical path of the extraction directory for Zip Slip protection
        String canonicalExtractPath = extractDir.getCanonicalPath();

        // Open and extract the ZIP file
        try (ZipFile zip = new ZipFile(zipFile)) {
            Enumeration<? extends ZipEntry> entries = zip.entries();

            while (entries.hasMoreElements()) {
                ZipEntry entry = entries.nextElement();
                String entryName = entry.getName();

                // Build the target file path
                File targetFile = new File(extractDir, entryName);

                // Zip Slip vulnerability protection: ensure the resolved path
                // is within the intended extraction directory
                String canonicalTargetPath = targetFile.getCanonicalPath();
                if (!canonicalTargetPath.startsWith(canonicalExtractPath + File.separator)
                        && !canonicalTargetPath.equals(canonicalExtractPath)) {
                    throw new IOException("ZIP entry is attempting to escape the target directory: " + entryName);
                }

                if (entry.isDirectory()) {
                    // Create directory entries
                    if (!targetFile.exists() && !targetFile.mkdirs()) {
                        throw new IOException("Failed to create directory: " + targetFile.getAbsolutePath());
                    }
                } else {
                    // Ensure parent directories exist for file entries
                    File parentDir = targetFile.getParentFile();
                    if (parentDir != null && !parentDir.exists()) {
                        if (!parentDir.mkdirs()) {
                            throw new IOException("Failed to create parent directory: " + parentDir.getAbsolutePath());
                        }
                    }

                    // Extract the file
                    extractEntry(zip, entry, targetFile);

                    // Add the absolute path of the extracted file to the result list
                    extractedFiles.add(targetFile.getAbsolutePath());
                }
            }
        }

        return extractedFiles;
    }

    /**
     * Extracts a single ZIP entry to the specified target file.
     *
     * @param zipFile    the ZipFile instance
     * @param entry      the ZIP entry to extract
     * @param targetFile the target file to write to
     * @throws IOException if an I/O error occurs during extraction
     */
    private void extractEntry(ZipFile zipFile, ZipEntry entry, File targetFile) throws IOException {
        try (InputStream inputStream = zipFile.getInputStream(entry);
             BufferedOutputStream outputStream = new BufferedOutputStream(
                     new FileOutputStream(targetFile), BUFFER_SIZE)) {

            byte[] buffer = new byte[BUFFER_SIZE];
            int bytesRead;
            while ((bytesRead = inputStream.read(buffer)) != -1) {
                outputStream.write(buffer, 0, bytesRead);
            }
        }
    }
}
